  1	import { useCallback, useState } from 'react';
  2	import { FormProvider, useForm, useWatch } from 'react-hook-form';
  3	import { useNavigate } from 'react-router-dom-v5-compat';
  4	import { getResourceUrl } from 'src/modules/Providers/utils/helpers/getResourceUrl';
  5	
  6	import { NetworkMapModelRef } from '@kubev2v/types';
  7	import {
  8	  Alert,
  9	  AlertActionCloseButton,
 10	  AlertVariant,
 11	  Button,
 12	  ButtonVariant,
 13	  Flex,
 14	  FlexItem,
 15	  Form,
 16	  Split,
 17	  Stack,
 18	} from '@patternfly/react-core';
 19	import { CreationMethod } from '@utils/analytics/constants';
 20	import { useForkliftAnalytics } from '@utils/analytics/hooks/useForkliftAnalytics';
 21	import { useForkliftTranslation } from '@utils/i18n';
 22	
 23	import { defaultNetworkMapping, NetworkMapFieldId } from '../constants';
 24	
 25	import CreateNetworkMapFieldTable from './fields/CreateNetworkMapFieldTable';
 26	import MapNameField from './fields/MapNameField';
 27	import ProjectSelectField from './fields/ProjectSelectField';
 28	import SourceProviderField from './fields/SourceProviderField';
 29	import TargetProviderField from './fields/TargetProviderField';
 30	import { createNetworkMap } from './utils/createNetworkMap';
 31	import type { CreateNetworkMapFormData } from './types';
 32	
 33	import './CreateNetworkMapForm.style.scss';
 34	
 35	const CreateNetworkMapForm: React.FC = () => {
 36	  const { t } = useForkliftTranslation();
 37	  const navigate = useNavigate();
 38	  const { trackEvent } = useForkliftAnalytics();
 39	
 40	  const form = useForm<CreateNetworkMapFormData>({
 41	    defaultValues: { [NetworkMapFieldId.NetworkMap]: [defaultNetworkMapping] },
 42	    mode: 'onChange',
 43	  });
 44	  const {
 45	    control,
 46	    formState: { isSubmitting, isValid },
 47	    getValues,
 48	    handleSubmit,
 49	  } = form;
 50	  const [createError, setCreateError] = useState<Error>();
 51	  const project = useWatch({
 52	    control,
 53	    name: NetworkMapFieldId.Project,
 54	  });
 55	
 56	  const networkMapsListUrl = getResourceUrl({
 57	    namespace: project,
 58	    reference: NetworkMapModelRef,
 59	  });
 60	
 61	  const trackNetworkMapEvent = useCallback(
 62	    (eventType: string, properties = {}) => {
 63	      trackEvent(eventType, { ...properties, creationMethod: CreationMethod.Form });
 64	    },
 65	    [trackEvent],
 66	  );
 67	
 68	  const clearError = useCallback(() => {
 69	    setCreateError(undefined);
 70	  }, []);
 71	
 72	  const onSubmit = useCallback(async () => {
 73	    setCreateError(undefined);
 74	
 75	    const { mapName, networkMap, sourceProvider, targetProvider } = getValues();
 76	
 77	    try {
 78	      const createdNetworkMap = await createNetworkMap({
 79	        mappings: networkMap,
 80	        name: mapName,
 81	        project,
 82	        sourceProvider,
 83	        targetProvider,
 84	        trackEvent: trackNetworkMapEvent,
 85	      });
 86	
 87	      const createdNetworkMapUrl = getResourceUrl({
 88	        name: createdNetworkMap.metadata?.name,
 89	        namespace: createdNetworkMap.metadata?.namespace,
 90	        reference: NetworkMapModelRef,
 91	      });
 92	
 93	      navigate(createdNetworkMapUrl);
 94	    } catch (error) {
 95	      setCreateError(error as Error);
 96	    }
 97	  }, [getValues, project, trackNetworkMapEvent, navigate]);
 98	
 99	  return (
100	    <FormProvider {...form}>
101	      <Flex
102	        direction={{ default: 'column' }}
103	        justifyContent={{ default: 'justifyContentSpaceBetween' }}
104	        alignItems={{ default: 'alignItemsStretch' }}
105	        flexWrap={{ default: 'nowrap' }}
106	        spaceItems={{ default: 'spaceItemsLg' }}
107	        className="pf-v6-u-h-100"
108	      >
109	        <Form className="create-network-map-form">
110	          <MapNameField />
111	          <ProjectSelectField />
112	          <SourceProviderField />
113	          <TargetProviderField />
114	          <CreateNetworkMapFieldTable />
115	        </Form>
116	
117	        <FlexItem>
118	          <Stack hasGutter>
119	            {createError?.message && (
120	              <Alert
121	                variant={AlertVariant.danger}
122	                title={t('Error creating network map')}
123	                actionClose={<AlertActionCloseButton onClose={clearError} />}
124	              >
125	                {createError.message}
126	              </Alert>
127	            )}
128	
129	            <Split hasGutter>
130	              <Button
131	                data-testid="network-map-create-button"
132	                onClick={handleSubmit(onSubmit)}
133	                isDisabled={!isValid || isSubmitting}
134	                isLoading={isSubmitting}
135	              >
136	                {t('Create')}
137	              </Button>
138	
139	              <Button
140	                variant={ButtonVariant.secondary}
141	                onClick={() => {
142	                  navigate(networkMapsListUrl);
143	                }}
144	              >
145	                {t('Cancel')}
146	              </Button>
147	            </Split>
148	          </Stack>
149	        </FlexItem>
150	      </Flex>
151	    </FormProvider>
152	  );
153	};
154	
155	export default CreateNetworkMapForm;

